    // for(auto x: *repeating_nodes){
    //     for(auto q: x.second[0]){
    //         if(x.first.find(q.tn)!=x.first.end()){
    //             cout << graph->seq[q.tn>>1].name << " ";
    //             // ha_sketch(graph->seq[q.tn>>1].seq, graph->seq[q.tn>>1].len, 30, 100, 0, 0, new ha_mz1_v(), nullptr);
