string get_haplotype_sequence(asg_t *graph, set<uint32_t> set_of_nodes, uint32_t begin, uint32_t end, int id, vector<uint32_t> *haplo_path, map<uint32_t, uint32_t> *node_pos)
{
    stringstream result;
    uint32_t node = begin;

    // 基础安全检查：确保起始节点合法
    if (node >> 1 >= graph->n_seq)
        return "";

    uint32_t num_outgoing_arcs = asg_arc_n(graph, node);
    asg_arc_t *outgoing_arcs = asg_arc_a(graph, node);
    set<uint32_t> visited_nodes;
    vector<uint32_t> visited_arcs;
    uint32_t current_pos = 0;
    map<uint32_t, uint32_t> positions;

    string pre_seq = string(graph->seq[node >> 1].seq);
    if (node & 1)
        pre_seq = complement(pre_seq);

    while (node != (uint32_t)-1)
    {
        visited_arcs.push_back(node);
        positions[node] = current_pos;
        visited_nodes.insert(node);

        if (node == end)
        {
            result << pre_seq;
            break;
        }

        map<uint32_t, asg_arc_t> next_node_arc;
        for (int i = 0; i < num_outgoing_arcs; i++)
        {
            next_node_arc[outgoing_arcs[i].v] = outgoing_arcs[i];
        }

        uint32_t next_node = (uint32_t)-1;
        uint32_t max_counter = 0;

        // --- 策略 1: 直接邻居搜索 ---
        for (auto const &[v_id, arc] : next_node_arc)
        {
            if (set_of_nodes.find(v_id >> 1) != set_of_nodes.end() && visited_nodes.find(v_id) == visited_nodes.end())
            {
                uint32_t n_out = asg_arc_n(graph, v_id);
                asg_arc_t *out_a = asg_arc_a(graph, v_id);
                uint32_t score = 0;
                for (int i = 0; i < n_out; i++)
                {
                    if (set_of_nodes.find(out_a[i].v >> 1) != set_of_nodes.end())
                        score++;
                }
                if (visited_nodes.find(v_id ^ 1) == visited_nodes.end())
                    score += 100;
                if (score >= max_counter)
                {
                    next_node = v_id;
                    max_counter = score;
                }
            }
        }

        // --- 策略 2: 孙子节点搜索 (备选) ---
        if (next_node == (uint32_t)-1)
        {
            bool found = false;
            for (int i = 0; i < num_outgoing_arcs; i++)
            {
                if (found)
                    break;
                uint32_t v_id = outgoing_arcs[i].v;
                uint32_t n_out_sec = asg_arc_n(graph, v_id);
                asg_arc_t *out_a_sec = asg_arc_a(graph, v_id);
                for (int j = 0; j < n_out_sec; j++)
                {
                    if (set_of_nodes.find(out_a_sec[j].v >> 1) != set_of_nodes.end() && visited_nodes.find(out_a_sec[j].v) == visited_nodes.end())
                    {
                        found = true;
                        next_node = v_id;
                        break;
                    }
                }
            }
        }

        // --- 退出机制 ---
        if (next_node == (uint32_t)-1)
        {
            cout << "[Warning] No available next node found, terminating at: " << graph->seq[node >> 1].name << endl;
            result << pre_seq; // 保存最后一个片段
            break;
        }

        // --- 拼接与更新 ---
        uint32_t overlap = 0;
        if (next_node_arc.count(next_node))
            overlap = next_node_arc[next_node].ol;

        // 安全计算长度，防止无符号数溢出
        uint32_t append_len = (pre_seq.length() > overlap) ? (pre_seq.length() - overlap) : 0;
        result << pre_seq.substr(0, append_len);
        current_pos += append_len;

        node = next_node;
        if (node >> 1 >= graph->n_seq)
            break; // 越界保护

        pre_seq = string(graph->seq[node >> 1].seq);
        if (node & 1)
            pre_seq = complement(pre_seq);

        num_outgoing_arcs = asg_arc_n(graph, node);
        outgoing_arcs = asg_arc_a(graph, node);
    }

    // cout << "Finalizing..." << endl;

    // 【最关键的修改：指针判空】
    if (haplo_path != nullptr)
        (*haplo_path) = visited_arcs;
    if (node_pos != nullptr)
        (*node_pos) = positions;

    return result.str();
}
