            outFileRECount << string(graph->seq[(*step.beg_node)[i >> 1] >> 1].name) + string("_") + string(string(graph->seq[(*step.end_node)[i >> 1] >> 1].name)) << "_haplo_" << (i % 2) + 1 << "\t" << "Back" << "\t" << back_re[i << 1] << endl;
