    //             cur_hap2 = complement(cur_hap2);
    //         }
    //         if(hap2[i]){
    //             result_hap1 << cur_hap2 << string(100, 'N');
    //             result_hap2 << cur_hap1 << string(100, 'N');
    //         }else{
