struct ContigPath
{
    std::string ctg_id;
    uint64_t ctg_length;
    string ctg_seq;
    std::vector<std::string> utg_path; // 按顺序存储utg_id
    std::vector<bool> utg_forward;     //
    std::vector<uint32_t> utg_starts;  // 每个utg在contig中的起始位置
    std::vector<uint64_t> utg_ends;    // 每个utg在contig中的结束位置
    std::vector<uint32_t> utg_nodes;
    bool is_only;
    uint64_t begin, end;
    uint32_t group_begin, group_end;
    int group_id;
    bool is_hap_only;
    int hap_id;
    map<uint32_t, uint32_t> node_positions;
};
struct UtgCtgMapping
{
    std::string utg_id;
    std::string ctg_id;
    uint64_t utg_length;
    uint64_t utg_start;
    uint64_t utg_end;
    uint64_t ctg_length;
    uint64_t ctg_start;
    uint64_t ctg_end;
    uint64_t shared_reads;
    uint64_t diff_dir_reads;
    uint64_t same_dir_reads;

    std::string orientation;
};

std::vector<UtgCtgMapping> utg_ctg_mappings;

// 打印contig路径信息（用于调试）
void print_contig_paths(std::unordered_map<std::string, ContigPath> &contig_paths)
{
    for (const auto &[ctg_id, path] : contig_paths)
    {
        fprintf(stderr, "Contig %s (length: %lu):\n", ctg_id.c_str(), path.ctg_length);
        for (size_t i = 0; i < path.utg_path.size(); i++)
        {
            fprintf(stderr, "  [%lu-%lu] %s  forward: %s \n",
                    path.utg_starts[i], path.utg_ends[i], path.utg_path[i].c_str(), path.utg_forward[i] ? "forward" : "reverse");
        }
    }
}

// 读取CSV文件并解析UTG-CTG映射
bool read_utg_ctg_mapping(const std::string &filename)
{
    std::ifstream file(filename);
    if (!file.is_open())
    {
        fprintf(stderr, "Error: Cannot open file %s\n", filename.c_str());
        return false;
    }

    std::string line;
    // 跳过标题行
    if (!std::getline(file, line))
    {
        fprintf(stderr, "Error: Empty file %s\n", filename.c_str());
        return false;
    }

    uint64_t line_count = 0;
    while (std::getline(file, line))
    {
        line_count++;
        std::stringstream ss(line);
        std::string token;
        UtgCtgMapping mapping;

        try
        {
            std::getline(ss, mapping.utg_id, ','); // 1
            std::getline(ss, token, ',');
            mapping.utg_length = std::stoull(token); // 2
            std::getline(ss, token, ',');
            mapping.utg_start = std::stoull(token); // 3
            std::getline(ss, token, ',');
            mapping.utg_end = std::stoull(token);  // 4
            std::getline(ss, mapping.ctg_id, ','); // 5
            std::getline(ss, token, ',');
            mapping.ctg_length = std::stoull(token); // 6
            std::getline(ss, token, ',');
            mapping.ctg_start = std::stoull(token); // 7
            std::getline(ss, token, ',');
            mapping.ctg_end = std::stoull(token); // 8
            std::getline(ss, token, ',');
            mapping.shared_reads = std::stoull(token); // 9
            std::getline(ss, token, ',');
            mapping.same_dir_reads = std::stoull(token); // 10
            std::getline(ss, token, ',');
            mapping.diff_dir_reads = std::stoull(token); // 11
            std::getline(ss, mapping.orientation, ',');  // 12  ← ⭐ 正确读取 orientation

            utg_ctg_mappings.push_back(mapping);
        }
        catch (const std::exception &e)
        {
            fprintf(stderr, "Error parsing line %lu: %s\n", line_count, line.c_str());
            fprintf(stderr, "Exception: %s\n", e.what());
            continue;
        }
    }

    file.close();
    fprintf(stderr, "Successfully read %lu UTG-CTG mappings from %s\n",
            utg_ctg_mappings.size(), filename.c_str());
    return true;
}

// 构建contig路径
bool build_contig_paths(std::unordered_map<std::string, ContigPath> &contig_paths)
{
    // 首先按contig分组
    std::unordered_map<std::string, std::vector<UtgCtgMapping>> ctg_groups;

    for (const auto &mapping : utg_ctg_mappings)
    {
        ctg_groups[mapping.ctg_id].push_back(mapping);
    }

    // 为每个contig构建路径
    for (auto &[ctg_id, mappings] : ctg_groups)
    {
        // 按contig_start排序，确保utg顺序正确
        std::sort(mappings.begin(), mappings.end(),
                  [](const UtgCtgMapping &a, const UtgCtgMapping &b)
                  {
                      return a.ctg_start < b.ctg_start;
                  });

        ContigPath path;
        path.ctg_id = ctg_id;
        path.ctg_length = mappings[0].ctg_length; // 所有mapping的ctg_length应该相同

        for (const auto &mapping : mappings)
        {
            path.utg_path.push_back(mapping.utg_id);
            path.utg_starts.push_back(mapping.ctg_start);
            path.utg_ends.push_back(mapping.ctg_end);
            // ⭐新增：写入 forward / reverse 方向
            if (mapping.orientation == "forward")
                path.utg_forward.push_back(true);
            else
                path.utg_forward.push_back(false);
        }

        contig_paths[ctg_id] = path;
    }

    fprintf(stderr, "Built paths for %lu contigs\n", contig_paths.size());
    return true;
}

void load_gfa_sequences(const std::string &gfa_file,
                        std::unordered_map<std::string, ContigPath> &contig_paths)
{
    if (gfa_file.empty())
    {
        fprintf(stderr, "Warning: GFA file path is empty\n");
        return;
    }

    std::ifstream file(gfa_file);
    if (!file.is_open())
    {
        fprintf(stderr, "Error: Cannot open GFA file: %s\n", gfa_file.c_str());
        return;
    }

    std::string line;
    int loaded_count = 0;
    int missed_count = 0;

    while (std::getline(file, line))
    {
        // 跳过空行和注释行
        if (line.empty() || line[0] == '#')
        {
            continue;
        }

        // 检查是否为S行
        if (line[0] == 'S')
        {
            std::istringstream iss(line);
            std::vector<std::string> tokens;
            std::string token;

            // 使用空格或制表符分割
            while (std::getline(iss, token, '\t'))
            {
                tokens.push_back(token);
            }

            // S行至少应该有3个字段：S, name, sequence
            if (tokens.size() >= 3)
            {
                std::string contig_name = tokens[1];
                std::string sequence = tokens[2];
                // if (contig_name.size() < 1000)
                //     cout << "contig_name:" << contig_name << endl;
                // 在contig_paths中查找对应的contig
                auto it = contig_paths.find(contig_name);
                if (it != contig_paths.end())
                {
                    // 找到contig，存储序列
                    it->second.ctg_seq = sequence;
                    loaded_count++;

                    // // 可选：记录序列长度用于调试
                    // it->second.ctg_len = sequence.length();
                }
                else
                {
                    // 可选：如果找不到，记录警告
                    if (missed_count < 10)
                    { // 只显示前10个未找到的警告
                        fprintf(stderr, "Warning: Contig '%s' found in GFA but not in contig_paths\n",
                                contig_name.c_str());
                    }
                    missed_count++;
                }
            }
            else
            {
                fprintf(stderr, "Warning: Malformed S line in GFA: %s\n", line.c_str());
            }
        }
    }

    file.close();

    fprintf(stderr, "Info: Loaded %d sequences from GFA file: %s\n", loaded_count, gfa_file.c_str());
    if (missed_count > 0)
    {
        fprintf(stderr, "Warning: %d contigs in GFA were not found in contig_paths\n", missed_count);
    }
}

void read_contig_csv(
    const std::string &utg_ctg_file,
    const std::string &hap1_gfa, // 新增：hap1 gfa文件路径
    const std::string &hap2_gfa, // 新增：hap2 gfa文件路径
    std::unordered_map<std::string, ContigPath> &contig_paths)
{

    // 读取UTG-CTG映射文件
    if (!utg_ctg_file.empty())
    {
        if (!read_utg_ctg_mapping(utg_ctg_file))
        {
            fprintf(stderr, "Error: Failed to read UTG-CTG mapping file\n");
            return;
        }

        // 构建contig路径
        if (!build_contig_paths(contig_paths))
        {
            fprintf(stderr, "Error: Failed to build contig paths\n");
            return;
        }
        // 读取gfa文件并将序列存入contig_paths
        load_gfa_sequences(hap1_gfa, contig_paths); // 加载hap1序列
        load_gfa_sequences(hap2_gfa, contig_paths); // 加载hap2序列
        // 可选：打印路径信息用于调试
        // print_contig_paths(contig_paths);
    }
    else
    {
        fprintf(stderr, "Warning: No UTG-CTG mapping file provided\n");
    }
}

std::vector<uint32_t> bfs_find_connection(asg_t *g, const std::string &name_first, const std::string &name_next)
{
    // 解析 utg 名称，提取数字部分
    std::string num_str = name_first.substr(3, 6);
    int num = std::stoi(num_str);
    uint32_t forward_idx = (num - 1) << 1;
    uint32_t reverse_idx = ((num - 1) << 1) + 1;

    // 保存路径节点
    std::vector<uint32_t> path_nodes;
    std::unordered_set<uint32_t> visited;

    // BFS 队列
    std::queue<std::pair<uint32_t, std::vector<uint32_t>>> q;

    // 初始化两个方向
    q.push({forward_idx, {forward_idx}});
    q.push({reverse_idx, {reverse_idx}});
    visited.insert(forward_idx);
    visited.insert(reverse_idx);

    // // 获取目标节点的两个方向编号
    // auto [target_forward, target_reverse] = get_utg_directions(name_next);

    // BFS 两轮（即最多两步延申）
    while (!q.empty())
    {
        auto [current, curr_path] = q.front();
        q.pop();

        // step 1: 查找所有出边
        asg_arc_t *out_arcs = asg_arc_a(g, current);
        uint32_t out_num = asg_arc_n(g, current);

        for (uint32_t i = 0; i < out_num; i++)
        {
            uint32_t next = out_arcs[i].v;

            // 如果已经访问过就跳过
            if (visited.count(next))
                continue;

            // 构造新路径
            std::vector<uint32_t> new_path = curr_path;

            new_path.push_back(next);
            cout << "递归调用：当前节点为" << current << "，下一个节点为" << next << endl;
            cout << "递归调用：当前节点为" << g->seq[current >> 1].name << "，下一个节点为" << g->seq[next >> 1].name << endl;
            // 判断是否为目标节点的任一方向
            if (g->seq[next >> 1].name == name_next)
            {
                // 返回完整路径（不含目标节点，只到前一个节点）
                cout << "找到连接路径：" << g->seq[current >> 1].name << "->" << g->seq[next >> 1].name << endl;
                return new_path;
            }

            // 限制两步延申
            if (new_path.size() <= 2)
            {
                q.push({next, new_path});
                visited.insert(next);
            }
        }
    }

    // 如果没找到目标节点
    return {};
}

// head 方向提供第2个，tail方向提供倒数第二个
static uint32_t find_seq_index_by_name(const asg_t *g, const std::string &name_first, const std::string &name_next, bool is_head)
{
    std::string num_str = name_first.substr(3, 6);
    int num = std::stoi(num_str);
    uint32_t forward_idx = (num - 1) << 1;
    uint32_t reverse_idx = ((num - 1) << 1) + 1;
    asg_arc_t *forward_out = asg_arc_a(g, forward_idx);
    uint32_t forward_num = asg_arc_n(g, forward_idx);
    asg_arc_t *reverse_out = asg_arc_a(g, reverse_idx);
    uint32_t reverse_num = asg_arc_n(g, reverse_idx);

    for (uint32_t i = 0; i < forward_num; i++)
    {
        string name = g->seq[forward_out[i].v >> 1].name;
        if (name_next == name)
        {
            if (is_head)
                return forward_idx;
            else
                return forward_out[i].v;
        }
    }
    for (uint32_t i = 0; i < reverse_num; i++)
    {
        string name = g->seq[reverse_out[i].v >> 1].name;
        if (name_next == name)
        {
            if (is_head)
                return reverse_idx;
            else
                return reverse_out[i].v;
        }
    }
    return -1;
}
static string find_node_for(const asg_t *g,
                            const std::string &hap_first,
                            const std::string &hap_end)
{
    auto name_to_idx = [&](const std::string &s) -> uint32_t
    {
        std::string num_str = s.substr(3, 6); // "utg" + 6 digits
        int num = std::stoi(num_str);
        return (num - 1) << 1; // forward idx
    };

    uint32_t h1_first_idx = name_to_idx(hap_first);
    uint32_t h1_end_idx = name_to_idx(hap_end);

    int node1 = 0, node2 = 0;
    if (node_type_global[h1_first_idx] != 3 || node_type_global[h1_first_idx ^ 1] != 3)
    {
        node1 = 1;
    }
    if (node_type_global[h1_end_idx] != 3 || node_type_global[h1_end_idx ^ 1] != 3)
    {
        node2 = 1;
    }
    if (node1 == 1 && node2 == 1)
        return "both";
    if (node1 == 1 && node2 == 0)
    {
        return "first";
    }
    if (node1 == 0 && node2 == 1)
    {
        return "second";
    }
}

static int find_forward_backward(const asg_t *g,
                                 const std::string &hap1_first,
                                 const std::string &hap1_end,
                                 const std::string &hap2_first,
                                 const std::string &hap2_end)
{
    auto name_to_idx = [&](const std::string &s) -> uint32_t
    {
        std::string num_str = s.substr(3, 6); // "utg" + 6 digits
        int num = std::stoi(num_str);
        return (num - 1) << 1; // forward idx
    };

    auto check_connection = [&](uint32_t node_idx,
                                const std::string &target1,
                                const std::string &target2) -> int
    {
        uint32_t forward_idx = node_idx;
        uint32_t reverse_idx = node_idx + 1;

        // Outgoing edges
        asg_arc_t *fw = asg_arc_a(g, forward_idx);
        uint32_t fw_n = asg_arc_n(g, forward_idx);

        asg_arc_t *rv = asg_arc_a(g, reverse_idx);
        uint32_t rv_n = asg_arc_n(g, reverse_idx);

        // Check forward direction
        for (uint32_t i = 0; i < fw_n; i++)
        {
            std::string name = g->seq[fw[i].v >> 1].name;

            if (name == target1)
                return 1;
            if (name == target2)
                return 2;
        }

        // Check reverse direction
        for (uint32_t i = 0; i < rv_n; i++)
        {
            std::string name = g->seq[rv[i].v >> 1].name;

            if (name == target1)
                return 1;
            if (name == target2)
                return 2;
        }

        return -1;
    };

    /******************************
     * Convert all node names
     ******************************/
    uint32_t h1_first_idx = name_to_idx(hap1_first);
    uint32_t h1_end_idx = name_to_idx(hap1_end);
    std::string h2_first = hap2_first;
    std::string h2_end = hap2_end;

    /******************************
     * Four combinations to check:
     ******************************/

    // 1. hap1_first → hap2_first / hap2_end
    {
        int r = check_connection(h1_first_idx, h2_first, h2_end);
        if (r == 1)
            return 1; // h1_first → h2_first
        if (r == 2)
            return 2; // h1_first → h2_end
    }

    // 2. hap1_end → hap2_first / hap2_end
    {
        int r = check_connection(h1_end_idx, h2_first, h2_end);
        if (r == 1)
            return 3; // h1_end → h2_first
        if (r == 2)
            return 4; // h1_end → h2_end
    }

    return -1;
}

void initialize_contig_paths(std::unordered_map<std::string, ContigPath> &contig_paths, asg_t *graph)
{
    std::cerr << "[INFO] Initializing contig paths and node paths..." << std::endl;

    // 遍历每一个 contig
    for (auto &kv : contig_paths)
    {
        ContigPath &ctg_path = kv.second;

        // // 如果这个 contig 只有一个 UTG，直接标记 is_only
        // if (ctg_path.utg_path.size() == 1)
        // {
        //     ctg_path.is_only = true;

        //     const std::string &utg_name = ctg_path.utg_path[0];
        //     // TODO: 根据名称计算 forward_idx
        //     uint32_t forward_idx = 0; // 这里填入你的转换逻辑
        //     ctg_path.utg_nodes.push_back(forward_idx);
        //     cout << "contig " << kv.first << " has only one UTG " << utg_name << endl;
        //     continue;
        // }

        //...........添加utg nodes。。。。。。。

        ctg_path.utg_nodes.clear();

        for (size_t i = 0; i < ctg_path.utg_path.size(); i++)
        {
            const std::string &name = ctg_path.utg_path[i];

            // 基本检查
            if (name.size() < 10 || name.substr(0, 3) != "utg")
            {
                std::cerr << "[Warning] Illegal utg name: " << name << "\n";
                continue;
            }

            // 提取数字部分（例如 utg000008l -> “000008”）
            std::string num_str = name.substr(3, 6);

            uint32_t utg_id = 0;
            try
            {
                // 你的 utg_id 是从 1 开始的，所以转换为 0-based
                utg_id = static_cast<uint32_t>(std::stoul(num_str)) - 1;
            }
            catch (...)
            {
                std::cerr << "[Warning] Failed to parse utg number from: " << name << "\n";
                continue;
            }

            // 获取方向：forward = true / reverse = false
            bool forward = ctg_path.utg_forward[i];

            // 生成 ASG node：<<1 为正向，|1 为反向
            uint32_t node = forward ? (utg_id << 1) : ((utg_id << 1) | 1);

            // 存入带方向位的节点
            ctg_path.utg_nodes.push_back(node);
        }

        if (ctg_path.utg_path.size() == 1)
        {
            ctg_path.is_only = true;
            continue;
        }

        ctg_path.begin = ctg_path.utg_nodes[0];
        ctg_path.end = ctg_path.utg_nodes.back();
        // 。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。
    }

    std::cerr << "[INFO] Finished initializing contig paths." << std::endl;
}

// 。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。。
// 匹配contig
static inline std::string get_utg_name(uint32_t node, asg_t *graph)
{
    return std::string(graph->seq[node >> 1].name);
}

void match_and_extend_contigs(
    std::unordered_map<std::string, ContigPath> &contig_paths,
    step_data &step,
    asg_t *graph)
{
    int hapN = step.beg_node->size() * 2;

    // ------- (1) 建立内部 contig 的 utg name 集合 -------
    std::vector<std::vector<std::string>> internal_contigs(hapN);
    for (int i = 0; i < hapN; i++)
    {
        for (uint32_t n : step.haplo_pathes[i])
            internal_contigs[i].push_back(get_utg_name(n, graph));
    }

    // ------- (2) 将外部 utg_path 转成集合 -------
    std::unordered_map<std::string,
                       std::unordered_set<std::string>>
        external_set;

    for (auto &kv : contig_paths)
    {
        const std::string &ctg = kv.first;
        const auto &path = kv.second;

        std::unordered_set<std::string> s;
        for (auto &u : path.utg_path)
            s.insert(u);

        external_set[ctg] = std::move(s);
    }

    // ------- (3) 匹配每个内部 contig 到最相似外部 contig -------
    std::vector<std::string> best_match(hapN, "");

    for (int i = 0; i < hapN; i++)
    {
        const auto &internal = internal_contigs[i];
        std::unordered_set<std::string> internal_set(
            internal.begin(), internal.end());

        int max_overlap = 0;
        std::string best_ctg = "";

        for (auto &kv : external_set)
        {
            const std::string &ctg = kv.first;
            const auto &s = kv.second;

            int overlap = 0;
            for (auto &u : internal_set)
            {
                if (s.count(u))
                    overlap++;
            }

            if (overlap > max_overlap)
            {
                max_overlap = overlap;
                best_ctg = ctg;
            }
        }

        best_match[i] = best_ctg;

        std::cerr << "[match] internal hap#" << i
                  << " best match external = " << best_ctg
                  << " overlap = " << max_overlap << "\n";
    }

    // ------- (4) 对匹配到外部 contig 的内部 contig 进行延伸 -------
    for (int i = 0; i < hapN; i++)
    {
        std::string ext = best_match[i];
        if (ext == "")
        {
            std::cerr << "[extend] internal hap#" << i
                      << " has no external match → keep as is\n";
            continue;
        }

        auto &ext_path = contig_paths[ext].utg_path;
        auto &int_path = internal_contigs[i];

        // 将内部转成 set，方便查找
        std::unordered_set<std::string> int_set(int_path.begin(), int_path.end());

        // --- 找内部第一个 utg 在外部的位置 ---
        int first_idx = -1;
        for (int k = 0; k < (int)ext_path.size(); k++)
        {
            if (int_path.size() > 0 && ext_path[k] == int_path[0])
            {
                first_idx = k;
                break;
            }
        }

        // --- 找内部最后一个 utg 在外部的位置 ---
        int last_idx = -1;
        for (int k = ext_path.size() - 1; k >= 0; k--)
        {
            if (ext_path[k] == int_path.back())
            {
                last_idx = k;
                break;
            }
        }

        if (first_idx == -1 || last_idx == -1)
        {
            std::cerr << "[extend] hap#" << i
                      << " external mapping failed. Skip.\n";
            continue;
        }

        // ------- (5) 构造最终延伸后的路径 -------
        std::vector<std::string> extended;

        // 加外部左侧
        for (int k = 0; k < first_idx; k++)
            extended.push_back(ext_path[k]);

        // 加内部
        for (auto &u : int_path)
            extended.push_back(u);

        // 加外部右侧
        for (int k = last_idx + 1; k < (int)ext_path.size(); k++)
            extended.push_back(ext_path[k]);

        // 替换
        std::cerr << "[extend] hap#" << i
                  << " extended len " << extended.size()
                  << " old len " << int_path.size() << "\n";

        internal_contigs[i] = extended;
    }

    // ------- (6) 输出最终结果 -------
    std::ofstream out(string("extended_contigs.txt"));
    for (int i = 0; i < hapN; i++)
    {
        out << ">internal_contig_" << i
            << "_best=" << best_match[i] << "\n";

        for (auto &u : internal_contigs[i])
            out << u << " ";
        out << "\n";
    }
    out.close();
}
