    //     // 遍历您的组装好的 chain
    //     for (const auto &chain : group_chains)
    //     {
    //         // 过滤无效的 chain
    //         if (chain.path_length == 0 || !chain.haplo_sequences || chain.contig_info_output.empty())
    //         {
