    //                 }
    //             }

    //             if (max_strength > 0)
    //             {
    //                 remaining_connections.emplace_back(max_strength, best_i_idx, best_j_idx, base_name_i, base_name_j);
    //             }
    //         }
    //     }

    //     // 按强度降序排序
    //     sort(remaining_connections.begin(), remaining_connections.end(),
    //          [](const auto &a, const auto &b)
    //          { return get<0>(a) > get<0>(b); });

